verification_commands.parse_inline_scripts:
@'
const fs = require('fs'); const vm = require('vm');
for (const file of ['index.html','public/index.html']) { const html=fs.readFileSync(file,'utf8'); const scripts=[...html.matchAll(/<script(?![^>]*\bsrc=)[^>]*>([\s\S]*?)<\/script>/gi)].map(m=>m[1]); scripts.forEach((code,i)=>new vm.Script(code,{filename:`${file}#inline-${i+1}`})); console.log(`${file}: parsed ${scripts.length} inline scripts OK`); }
'@ | node -
